import test from 'node:test'
import assert from 'node:assert/strict'
import { parseArgs } from './src/parseArgs.mjs'

test('parseArgs handles booleans, values, equals syntax, and positionals', () => {
  assert.deepEqual(parseArgs(['--verbose', '--count', '3', '--output=dist', 'src/index.js']), {
    _: ['src/index.js'],
    verbose: true,
    count: '3',
    output: 'dist'
  })
})

test('parseArgs handles boolean flags at end', () => {
  assert.deepEqual(parseArgs(['--foo']), { _: [], foo: true })
})

test('parseArgs handles short flag with value', () => {
  assert.deepEqual(parseArgs(['-v', 'val']), { _: [], v: 'val' })
})

test('parseArgs handles short flag with equals', () => {
  assert.deepEqual(parseArgs(['-v=123']), { _: [], v: '123' })
})

test('parseArgs handles empty argv', () => {
  assert.deepEqual(parseArgs([]), { _: [] })
})

test('parseArgs handles only positionals', () => {
  assert.deepEqual(parseArgs(['pos1', 'pos2']), { _: ['pos1', 'pos2'] })
})

test('parseArgs handles mixed short flags', () => {
  assert.deepEqual(parseArgs(['-a', 'b', '-c']), { _: [], a: 'b', c: true })
})

test('parseArgs handles flag with value followed by another flag', () => {
  assert.deepEqual(parseArgs(['--foo', 'bar', '--baz']), { _: [], foo: 'bar', baz: true })
})

